const AuthContext = React.createContext();

function useAuth() {
  return React.useContext(AuthContext);
}

function App() {
  const { user, login, logout, loading } = useAuth();

  if (loading) {
    return <div style={styles.container}><div>Loading...</div></div>;
  }

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h1 style={styles.title}>OpenID Connect SPA</h1>
        {!user ? (
          <div>
            <p style={styles.text}>Please log in to continue</p>
            <button onClick={login} style={styles.button}>
              Login with OpenID Connect
            </button>
          </div>
        ) : (
          <div>
            <h2 style={styles.subtitle}>Welcome!</h2>
            <div style={styles.profile}>
              {user.picture && (
                <img src={user.picture} alt="Profile" style={styles.avatar} />
              )}
              <div style={styles.info}>
                <p><strong>Name:</strong> {user.name || 'N/A'}</p>
                <p><strong>Email:</strong> {user.email || 'N/A'}</p>
                <p><strong>Subject:</strong> {user.sub}</p>
              </div>
            </div>
            <button onClick={logout} style={styles.buttonSecondary}>
              Logout
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

